sql:
SELECT COUNT(DISTINCT player_id) AS total_players_completed_missions
FROM player_missions
WHERE status = 'completed';

SELECT COUNT(DISTINCT pm.mission_id) AS total_missions_claimed
FROM player_missions pm
WHERE pm.reward_claimed = 1;

external_knowledge:
- "Conquered the most missions" refers to the player who has completed the highest number of missions, represented by the `total_missions_completed` column; 
- "Claimed the most rewards" refers to the player who has earned the highest number of rewards, represented by the `total_rewards_earned` column; 
- "Top 5" implies ranking the players by their total missions completed and total rewards earned in descending order and selecting the top 5.
